#include <bits/stdc++.h>
#define int long long
using namespace std;
const int INF = 1e18;
const int N = 105;
const int M = 25;
int lx[M], size[M], ly[M], col[M], rx[M], ry[M];
int n, a[N][N], dp[1 << 16 + 1][M], up[M][M];
bool in (int i, int s) {
	return (s >> (i - 1)) & 1;
}
bool ok (int i, int S) {
	bool flag = true;
	for (int j = 1; j <= size[i] && flag; j++) {
		flag &= in (up[i][j], S);
	}
	return flag;
}
signed main () {
	ios::sync_with_stdio (0);
	cin.tie (0), cout.tie (0);
	cin >> n;
	for (int i = 1; i <= n; i++) {
		cin >> lx[i] >> ly[i] >> rx[i] >> ry[i] >> col[i];
		for (int x = lx[i]; x < rx[i]; x++) {
			for (int y = ly[i]; y < ry[i]; y++) {
				a[x][y] = i;
			}
		} 
	}
    for (int i = 1; i <= n; i++) {
    	if (!lx[i]) {
    		continue;
		}
        lx[i]--;
        for (int j = ly[i] + 1; j <= ry[i]; j++) {
        	if (a[lx[i]][j] != a[lx[i]][j - 1]) {
        		up[i][++size[i]] = a[lx[i]][j - 1];
			}
		}
		if (a[lx[i]][ry[i]] == a[lx[i]][ry[i] - 1]) {
			up[i][++size[i]] = a[lx[i]][ry[i] - 1];
		}
    }
    memset (dp, 0x3f, sizeof (dp));
    for (int i = 1; i <= 20; i++) {
    	dp[0][i] = 1;
	}
    for (int i = 1; i < (1 << n); i++) {
    	for (int j = 1; j <= n; j++) {
    		if (in (j, i) && ok (j, i)) {
    			for (int k = 1; k <= 20; k++) {
    				if (k != col[j]) {
    					if (dp[i][col[j]] > dp[i - (1 << (j - 1))][k] + 1) {
    						dp[i][col[j]] = dp[i - (1 << (j - 1))][k] + 1;
						}
					}
				}
				if (dp[i][col[j]] > dp[i - (1 << (j - 1))][col[j]]) {
					dp[i][col[j]] = dp[i - (1 << (j - 1))][col[j]];
				}
			}
		}
	}
    int ans = INF;
    for (int i = 1; i <= 20; i++) {
    	if (ans > dp[(1 << n) - 1][i]) {
    		ans = dp[(1 << n) - 1][i];
		}
	}
    cout << ans;
	return 0;
}
